import{_ as e,o as l,c as n,a2 as t}from"./chunks/framework.BFVZdVmd.js";const k=JSON.parse('{"title":"链路追踪（SkyWalking / OpenTelemetry）","description":"","frontmatter":{},"headers":[],"relativePath":"observability/skywalking.md","filePath":"observability/skywalking.md","lastUpdated":null}'),i={name:"observability/skywalking.md"};function s(r,a,o,c,d,p){return l(),n("div",null,[...a[0]||(a[0]=[t(`<h1 id="链路追踪-skywalking-opentelemetry" tabindex="-1">链路追踪（SkyWalking / OpenTelemetry） <a class="header-anchor" href="#链路追踪-skywalking-opentelemetry" aria-label="Permalink to &quot;链路追踪（SkyWalking / OpenTelemetry）&quot;">​</a></h1><h2 id="是什么" tabindex="-1">是什么 <a class="header-anchor" href="#是什么" aria-label="Permalink to &quot;是什么&quot;">​</a></h2><ul><li><code>SkyWalking</code>：开源 APM，分布式链路追踪、性能分析，国内项目常用。</li><li><code>OpenTelemetry</code>：可观测性标准（指标、链路、日志统一规范），新项目推荐关注。</li><li><code>Zipkin</code>：轻量级链路追踪系统。</li><li><code>Tempo</code>：Grafana 生态的 Trace 存储。</li></ul><h2 id="解决什么问题" tabindex="-1">解决什么问题 <a class="header-anchor" href="#解决什么问题" aria-label="Permalink to &quot;解决什么问题&quot;">​</a></h2><p>微服务一个请求会穿过多个服务，出问题时很难定位是哪一环慢、哪一环报错。链路追踪给每个请求分配 <code>traceId</code>，串起整条调用链，定位性能瓶颈和异常节点。</p><h2 id="典型调用链" tabindex="-1">典型调用链 <a class="header-anchor" href="#典型调用链" aria-label="Permalink to &quot;典型调用链&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>前端</span></span>
<span class="line"><span>  -&gt; Gateway        (traceId=abc)</span></span>
<span class="line"><span>  -&gt; user-service   (traceId=abc)</span></span>
<span class="line"><span>  -&gt; order-service  (traceId=abc)</span></span>
<span class="line"><span>  -&gt; payment-service(traceId=abc)</span></span></code></pre></div><p>同一个 <code>traceId</code> 贯穿所有服务，可以还原完整调用路径和每段耗时。</p><h2 id="选型建议" tabindex="-1">选型建议 <a class="header-anchor" href="#选型建议" aria-label="Permalink to &quot;选型建议&quot;">​</a></h2><ul><li>国内项目用得最多的是 <code>SkyWalking</code>，无侵入（Java Agent 方式），部署即用。</li><li>新项目推荐关注 <code>OpenTelemetry</code>，它是更通用的可观测性标准，能统一指标、链路、日志的采集，避免被单一厂商绑定。</li><li>链路追踪要和<a href="./logging">日志</a>的 <code>traceId</code> 打通，才能从一条慢请求直接跳到对应日志。</li></ul><h2 id="配套" tabindex="-1">配套 <a class="header-anchor" href="#配套" aria-label="Permalink to &quot;配套&quot;">​</a></h2><ul><li>指标监控见 <a href="./prometheus-grafana">Prometheus + Grafana</a>。</li><li>日志全链路见<a href="./logging">日志体系</a>。</li></ul>`,12)])])}const u=e(i,[["render",s]]);export{k as __pageData,u as default};
